import re
from pathlib import Path

root = Path(__file__).resolve().parent.parent
js_files = list((root / 'js').glob('*.js'))
pattern = re.compile(r'style\.innerHTML=`.*?`;document\.head\.appendChild\(style\);', re.DOTALL)
new_css = """style.innerHTML=`html.dark-mode body{background-color:#050505 !important;color:#f8fafc !important;}html.dark-mode header,html.dark-mode footer,html.dark-mode nav,html.dark-mode .settings-sidebar,html.dark-mode .settings-content,html.dark-mode .order-card,html.dark-mode .product-card,html.dark-mode .sp-media,html.dark-mode form,html.dark-mode .order-summary,html.dark-mode .product-modal-content,html.dark-mode .cart-content,html.dark-mode .pm-details,html.dark-mode .pm-image-container,html.dark-mode .accordion-header,html.dark-mode .hero,html.dark-mode .card,html.dark-mode .info-panel,html.dark-mode .editor-box,html.dark-mode .order-header,html.dark-mode .order-total,html.dark-mode .empty-state{background-color:#111 !important;color:#f8fafc !important;border-color:#222 !important;}html.dark-mode input,html.dark-mode select,html.dark-mode textarea,html.dark-mode .search-input,html.dark-mode .header-search-container input{background-color:#111 !important;color:#f8fafc !important;border-color:#333 !important;}html.dark-mode h1,html.dark-mode h2,html.dark-mode h3,html.dark-mode h4,html.dark-mode strong,html.dark-mode .product-title,html.dark-mode .pm-title,html.dark-mode .item-price,html.dark-mode .total-amount,html.dark-mode .total-price,html.dark-mode #total-amount,html.dark-mode .order-value,html.dark-mode .order-label,html.dark-mode .order-date-val,html.dark-mode .item-name,html.dark-mode .item-qty{color:#fff !important;}html.dark-mode .logo{color:#fff !important;}html.dark-mode .btn-outline{color:#fff !important;border-color:#fff !important;background:transparent !important;}html.dark-mode .btn-outline:hover{background:rgba(255,255,255,0.1) !important;color:#fff !important;}html.dark-mode .btn{background-color:#2563eb !important;color:#fff !important;border-color:#2563eb !important;}html.dark-mode .btn:hover{background-color:#1d4ed8 !important;border-color:#1d4ed8 !important;}html.dark-mode .settings-menu-btn{color:#d1d5db !important;border-color:#2b2b2b !important;background:transparent !important;}html.dark-mode .settings-menu-btn:hover,html.dark-mode .settings-menu-btn.active{background-color:#111 !important;color:#fff !important;border-left-color:#fff !important;}html.dark-mode .empty-state,html.dark-mode .order-header,html.dark-mode .accordion-content,html.dark-mode .cart-table th,html.dark-mode .cart-table td,html.dark-mode .total-row,html.dark-mode .summary-row,html.dark-mode .item-row{background-color:#111 !important;border-color:#222 !important;color:#d1d5db !important;}html.dark-mode .track-line-bg{background:#333 !important;}html.dark-mode .step-counter{background:#111 !important;border-color:#333 !important;color:#d1d5db !important;}html.dark-mode .stepper-item.active .step-counter{border-color:#fff !important;color:#fff !important;background:#000 !important;}html.dark-mode .stepper-item.completed .step-counter{background:#fff !important;border-color:#fff !important;color:#000 !important;}html.dark-mode .filter-btn{background-color:#111 !important;color:#d1d5db !important;border-color:#333 !important;}html.dark-mode .filter-btn:hover,html.dark-mode .filter-btn.active{background-color:#fff !important;color:#000 !important;border-color:#fff !important;}html.dark-mode .filter-chip{background:#111 !important;color:#aaa !important;border-color:#333 !important;}html.dark-mode .filter-chip.active{background:#fff !important;color:#000 !important;}html.dark-mode .dropdown-menu{background:#111 !important;border-color:#333 !important;}html.dark-mode .dropdown-menu a{color:#ccc !important;}html.dark-mode .dropdown-menu a:hover{background:#222 !important;color:#fff !important;}html.dark-mode .sp-media{background:transparent !important;}html.dark-mode .profile-info h2,html.dark-mode .profile-info p{color:#fff !important;}html.dark-mode .sp-description,html.dark-mode .pm-description{color:#ccc !important;}html.dark-mode div:where(.swal2-container) div:where(.swal2-popup){background-color:#111 !important;color:#fff !important;border:1px solid #333 !important;}html.dark-mode div:where(.swal2-title){color:#fff !important;}html.dark-mode div:where(.swal2-html-container){color:#ccc !important;}`;document.head.appendChild(style);"""
count = 0
for path in js_files:
    text = path.read_text(encoding='utf-8')
    if 'style.innerHTML=`html.dark-mode body{background-color:#000 !important;color:#fff !important;}' in text:
        new_text, n = pattern.subn(new_css, text)
        if n == 1:
            path.write_text(new_text, encoding='utf-8')
            count += 1
        else:
            print(f'WARNING no replacement in {path} (matched {n})')
print(f'Updated {count} files')
